chart.config_raw:
const ctx = document.getElementById('adoptionChart').getContext('2d');
  new Chart(ctx, {
    type: 'bar',
    data: {
      labels: [
        'Industrial-era\noperating model',
        'Digital-era\n(agile / product & platform)',
        'Decentralised\nnetwork'
      ],
      datasets: [{
        label: '% of organisations',
        data: [89, 9, 1],
        backgroundColor: ['#f6ad55', '#4dabf7', '#51cf66'],
        borderRadius: 6,
        barThickness: 64
      }]
    },
    options: {
      animation: false,
      responsive: true,
      maintainAspectRatio: true,
      plugins: {
        legend: { display: false },
        tooltip: {
          callbacks: {
            label: function(context) {
              return context.parsed.y + '%';
            }
          }
        }
      },
      scales: {
        y: {
          beginAtZero: true,
          max: 100,
          ticks: {
            callback: function(value) { return value + '%'; },
            font: { size: 12 },
            color: '#4a5568'
          },
          grid: { color: '#e2e8f0' },
          title: {
            display: true,
            text: 'Share of organisations',
            font: { size: 12, weight: 'bold' },
            color: '#4a5568'
          }
        },
        x: {
          ticks: {
            font: { size: 11 },
            color: '#4a5568',
            maxRotation: 0
          },
          grid: { display: false }
        }
      }
    }
  });
